/**
 * Generated by `createservice acquiring.RegisterExternalPaymentsService`
 */
const Big = require('big.js')
const dayjs = require('dayjs')

const { GQLError } = require('@open-condo/keystone/errors')
const { checkDvAndSender } = require('@open-condo/keystone/plugins/dvAndSender')
const { GQLCustomSchema, getByCondition, find } = require('@open-condo/keystone/schema')

const access = require('@condo/domains/acquiring/access/RegisterExternalPaymentsService')
const { CONTEXT_FINISHED_STATUS } = require('@condo/domains/acquiring/constants/context')
const { ACQUIRING_INTEGRATION_EXTERNAL_IMPORT_TYPE } = require('@condo/domains/acquiring/constants/integration')
const {
    DEFAULT_MULTIPAYMENT_SERVICE_CATEGORY,
    MULTIPAYMENT_DONE_STATUS,
    PAYMENT_DONE_STATUS,
} = require('@condo/domains/acquiring/constants/payment')
const { ERRORS, PAYMENTS_LIMIT } = require('@condo/domains/acquiring/constants/registerExternalPayments')
const { Payment, MultiPayment } = require('@condo/domains/acquiring/utils/serverSchema')
const { ISO_CODES } = require('@condo/domains/common/constants/currencies')

function validatePayments (payments, context) {
    for (const payment of payments) {
        const { transactionId, amount, period, transactionDate, depositedDate, currencyCode, explicitFee, implicitFee } = payment

        if (!ISO_CODES.includes(currencyCode)) {
            throw new GQLError({ ...ERRORS.INVALID_CURRENCY_CODE, messageInterpolation: { currencyCode, transactionId } }, context)
        }

        if (!dayjs(period, 'YYYY-MM-01', true).isValid()) {
            throw new GQLError({ ...ERRORS.INVALID_PERIOD_FORMAT, messageInterpolation: { period, transactionId } }, context)
        }

        if (dayjs(transactionDate).toISOString() !== transactionDate) {
            throw new GQLError({ ...ERRORS.INVALID_DATE_FORMAT, messageInterpolation: { date: transactionDate, transactionId } }, context)
        }
        if (depositedDate && dayjs(depositedDate).toISOString() !== depositedDate) {
            throw new GQLError({ ...ERRORS.INVALID_DATE_FORMAT, messageInterpolation: { date: depositedDate, transactionId } }, context)
        }

        try {
            Big(amount)
            if (explicitFee) Big(explicitFee)
            if (implicitFee) Big(implicitFee)
        } catch (e) {
            throw new GQLError({ ...ERRORS.INVALID_PAYMENT_AMOUNT, messageInterpolation: { amount, transactionId } }, context)
        }

        if (Big(amount).lte(0)) {
            throw new GQLError({ ...ERRORS.NEGATIVE_PAYMENT_AMOUNT, messageInterpolation: { amount, transactionId } }, context)
        }
    }
}

const RegisterExternalPaymentsService = new GQLCustomSchema('RegisterExternalPaymentsService', {
    types: [
        {
            access: true,
            type: 'input ExternalPaymentsInput { accountNumber: String!, tin: String!, bankAccount: String!, routingNumber: String!, address: String!, period: String!, depositedDate: String, transactionDate: String!, transactionId: String!, amount: String!, explicitFee: String, implicitFee: String, paymentOrder: String!, currencyCode: String! }',
        },
        {
            access: true,
            type: 'input RegisterExternalPaymentsInput { dv: Int!, sender: SenderFieldInput!, acquiringIntegrationContext: AcquiringIntegrationContextWhereUniqueInput!, payments: [ExternalPaymentsInput!]! }',
        },
        {
            access: true,
            type: 'type RegisterExternalPaymentsOutput { status: String! }',
        },
    ],

    mutations: [
        {
            access: access.canRegisterExternalPayments,
            schema: 'registerExternalPayments(data: RegisterExternalPaymentsInput!): RegisterExternalPaymentsOutput',
            doc: {
                summary: 'Registers external payments',
            },
            resolver: async (parent, args, context) => {
                const { data } = args
                const { sender, payments: paymentsInput, acquiringIntegrationContext: acquiringContextInput } = data

                checkDvAndSender(data, ERRORS.DV_VERSION_MISMATCH, ERRORS.WRONG_SENDER_FORMAT, context)
                if (paymentsInput.length > PAYMENTS_LIMIT) throw new GQLError(ERRORS.PAYMENTS_LIMIT_EXCEEDED, context)

                const acquiringContext = await getByCondition('AcquiringIntegrationContext', {
                    id: acquiringContextInput.id,
                    status: CONTEXT_FINISHED_STATUS,
                    deletedAt: null,
                })
                if (!acquiringContext) throw new GQLError(ERRORS.ACQUIRING_CONTEXT_NOT_FOUND, context)

                const acquiringIntegration = await getByCondition('AcquiringIntegration', {
                    id: acquiringContext.integration,
                    type: ACQUIRING_INTEGRATION_EXTERNAL_IMPORT_TYPE,
                    deletedAt: null,
                })
                if (!acquiringIntegration) throw new GQLError(ERRORS.ACQUIRING_INTEGRATION_NOT_FOUND, context)

                const externalIds = paymentsInput.map(({ transactionId }) => transactionId)
                if (new Set(externalIds).size !== externalIds.length) throw new GQLError({ ...ERRORS.DUPLICATED_PAYMENTS, messageInterpolation: { ids: externalIds.join(', ') } }, context)

                const existingMultiPayments = await find('MultiPayment', {
                    integration: { id: acquiringIntegration.id },
                    transactionId_in: externalIds,
                    payments_some: { organization: { id: acquiringContext.organization } },
                    deletedAt: null,
                })

                if (existingMultiPayments.length > 0) {
                    const ids = existingMultiPayments.map(p => p.transactionId).join(', ')
                    throw new GQLError({ ...ERRORS.DUPLICATED_PAYMENTS, messageInterpolation: { ids } }, context)
                }

                validatePayments(paymentsInput, context)

                for (const input of paymentsInput) {
                    const payment = await Payment.create(context, {
                        dv: 1, sender,
                        status: PAYMENT_DONE_STATUS,
                        amount: Big(input.amount).toString(),
                        explicitFee: Big(input.explicitFee || 0).toString(),
                        implicitFee: Big(input.implicitFee || 0).toString(),
                        currencyCode: input.currencyCode,
                        accountNumber: input.accountNumber,
                        period: input.period,
                        recipientBic: input.routingNumber,
                        recipientBankAccount: input.bankAccount,
                        advancedAt: input.transactionDate,
                        depositedDate: input.depositedDate ? input.depositedDate : input.transactionDate,
                        rawAddress: input.address,
                        order: input.paymentOrder,
                        organization: { connect: { id: acquiringContext.organization } },
                        context: { connect: { id: acquiringContext.id } },
                    })

                    await MultiPayment.create(context, {
                        dv: 1, sender,
                        status: MULTIPAYMENT_DONE_STATUS,
                        amountWithoutExplicitFee: Big(input.amount).toString(),
                        explicitFee: Big(input.explicitFee || 0).toString(),
                        implicitFee: Big(input.implicitFee || 0).toString(),
                        explicitServiceCharge: Big(0).toString(),
                        currencyCode: input.currencyCode,
                        integration: { connect: { id: acquiringIntegration.id } },
                        payments: { connect: [{ id: payment.id }] },
                        serviceCategory: DEFAULT_MULTIPAYMENT_SERVICE_CATEGORY,
                        transactionId: input.transactionId,
                        withdrawnAt: input.transactionDate,
                    })
                }

                return { status: 'ok' }
            },
        },
    ],
})

module.exports = {
    RegisterExternalPaymentsService,
}